function onEdit(e) {                                                                    
    if (!e) return;

    var sheet = e.source.getActiveSheet();
    var range = e.range;
    var checkboxColumn = 20;
    var timeColumn = 21;                                                                  

    if (range.getColumn() == checkboxColumn && range.getValue() === true) {               
      sheet.getRange(range.getRow(), timeColumn).setValue(new Date());                    
    }                                                                                     

    if (range.getColumn() == checkboxColumn && range.getValue() === false) {              
      sheet.getRange(range.getRow(), timeColumn).clearContent();
    }                                                                                     
  }

